import{_ as r,o as t,c as p,j as e,a as n,a1 as s}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"2.6.1.身份专长","description":"","frontmatter":{},"headers":[],"relativePath":"1.基础规则/2.建卡相关/2.6.专长/2.6.1.身份专长.md","filePath":"1.基础规则/2.建卡相关/2.6.专长/2.6.1.身份专长.md"}'),o={name:"1.基础规则/2.建卡相关/2.6.专长/2.6.1.身份专长.md"};function _(d,a,l,i,c,b){return t(),p("div",null,[...a[0]||(a[0]=[e("h1",{id:"_2-6-1-身份专长",tabindex:"-1"},[n("2.6.1.身份专长 "),e("a",{class:"header-anchor",href:"#_2-6-1-身份专长","aria-label":'Permalink to "2.6.1.身份专长"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：新世短歌038")])])],-1),s('<h1 id="身份专长" tabindex="-1">身份专长 <a class="header-anchor" href="#身份专长" aria-label="Permalink to &quot;身份专长&quot;">​</a></h1><p>身份专长<br> 若未特殊说明，则你获得的任何属性或技能专业点数，均不可超过上限。</p><p>身份专长的价格为专长等级*1点专长点。</p><p>特殊身份（0、1、2、3、4、5）<br> 特殊：特殊身份只能在你建卡时选择。本专长无须逐级购买，玩家可自由选择购买除零级外的任意一级（或一项）专长。玩家可重复购本专长以获得不同级别的效果。</p><p>零珠片玉<br> 零珠片玉在你既没有选择天命也没有选择特殊身份时自动获得，不视为一种特殊身份。<br> 在第一场影片结束后获得1点自由属性点。</p><p>一技之长<br> 你指定一项初始等级不超过3级的技能，将其提升1级</p><p>二極归中<br> 你建卡时可以额外获得1点自由技能点与4点自由专业点，但仍需遵循建卡规则</p><p>三教九流<br> 你建卡时可以额外获得2点自由技能点，并将9个不同技能下的专业等级由0提升至1.但仍需遵循建卡规则</p><p>四裔御守<br> 你指定三项初始等级为2级的技能，将其提升至3级</p><p>五星出东<br> 选择一件价格不超过D+500的物品或一种价格不超过D+600的强化，立即获得之。特殊的，若选择的是强化，则不会获得其提供的的属性直至经历的第一场影片结束</p><p>身份专长与天命视为互斥，若无特殊说明，则无法在拥有一项天命时获得一项身份专长。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',13)])])}const m=r(o,[["render",_]]);export{f as __pageData,m as default};
